transforms.code:
# Define database name
dbName = "mes_core"

# Define the query for the productcode table (PostgreSQL)
query = "SELECT productcode AS \"ProductCode\", description AS \"Description\", disable AS \"Disable\", \"TimeStamp\" FROM productcode"
try:
    # Execute the query
    data = system.db.runPrepQuery(query, [], dbName)

    # Convert dataset to JSON for Perspective compatibility
    json_data = system.dataset.toPyDataSet(data)
    result = [
        {
            col: row[col]
            for col in data.getColumnNames()
        }
        for row in json_data
    ]
    return result

except Exception as e:
    system.util.getLogger("ScriptLogger").error("Query failed: {}".format(str(e)))
    return []
